-- Dump Ajustado para VPS (Schemas hub e core)
CREATE SCHEMA IF NOT EXISTS hub;
CREATE SCHEMA IF NOT EXISTS core;


CREATE TABLE IF NOT EXISTS hub.assessores (
    id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(),
    nome TEXT NOT NULL,
    email TEXT,
    telefone TEXT,
    regiao_atuacao TEXT,
    municipios_cobertos INTEGER,
    liderancas_gerenciadas INTEGER,
    status TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    avatar_url TEXT,
    cargo TEXT,
    latitude NUMERIC,
    longitude NUMERIC,
    origem TEXT DEFAULT Alê Portela,
    endereco JSONB
);

CREATE TABLE IF NOT EXISTS hub.municipios (
    id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(),
    nome TEXT NOT NULL,
    regiao TEXT,
    populacao INTEGER,
    idh NUMERIC,
    pib_per_capita NUMERIC,
    influencia TEXT,
    liderancas_ativas INTEGER,
    status_atividade TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    assessor_id UUID,
    codigo_ibge CHARACTER VARYING,
    status_prefeito TEXT,
    idene BOOLEAN,
    lincoln_fechado BOOLEAN,
    status_atendimento TEXT,
    tipo_atendimento TEXT,
    principal_demanda TEXT,
    sugestao_sedese TEXT,
    observacao TEXT,
    votacao_ale INTEGER,
    votacao_lincoln INTEGER
);

CREATE TABLE IF NOT EXISTS hub.apoiadores (
    id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(),
    municipio_id UUID,
    nome TEXT NOT NULL,
    cargo TEXT,
    telefone TEXT,
    endereco TEXT,
    email TEXT,
    foto_url TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    status_prefeito TEXT,
    votacao_ale INTEGER,
    votacao_lincoln INTEGER,
    principal_demanda TEXT,
    sugestao_sedese TEXT
);

CREATE TABLE IF NOT EXISTS hub.liderancas (
    id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(),
    nome TEXT NOT NULL,
    partido TEXT,
    cargo TEXT,
    municipio_nome TEXT,
    telefone TEXT,
    email TEXT,
    status TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    origem TEXT DEFAULT Alê Portela,
    regiao TEXT,
    avatar_url TEXT,
    endereco JSONB,
    latitude NUMERIC,
    longitude NUMERIC
);

CREATE TABLE IF NOT EXISTS hub.liderancas_locais (
    id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(),
    municipio_id UUID,
    nome TEXT NOT NULL,
    partido TEXT,
    cargo TEXT,
    avatar_initials TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    origem TEXT DEFAULT Alê Portela
);

CREATE TABLE IF NOT EXISTS hub.votos (
    id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(),
    municipio_id UUID,
    ano INTEGER NOT NULL,
    cargo TEXT NOT NULL,
    quantidade INTEGER,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS hub.eleitorado (
    id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(),
    municipio_id UUID,
    total INTEGER,
    genero_feminino INTEGER,
    genero_masculino INTEGER,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS hub.demandas (
    id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(),
    municipio_id UUID,
    titulo TEXT NOT NULL,
    descricao TEXT,
    status TEXT,
    prioridade TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    origem TEXT DEFAULT Alê Portela,
    solicitante TEXT,
    recebido_por TEXT,
    atribuido_a TEXT,
    redirecionado_para TEXT,
    area_responsavel TEXT,
    historico_redirecionamentos JSONB
);

CREATE TABLE IF NOT EXISTS hub.solicitacoes_agenda (
    id UUID NOT NULL PRIMARY KEY,
    solicitante TEXT NOT NULL,
    titulo TEXT NOT NULL,
    descricao TEXT,
    data DATE NOT NULL,
    hora_inicio TIME WITHOUT TIME ZONE NOT NULL,
    hora_fim TIME WITHOUT TIME ZONE NOT NULL,
    local TEXT,
    status TEXT DEFAULT Pendente,
    origem TEXT NOT NULL,
    municipio_id UUID,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    assessor_responsavel TEXT,
    estimativa_publico INTEGER,
    tipo_evento TEXT,
    tipo_local TEXT,
    tempo_participacao TEXT,
    horario_chegada TIME WITHOUT TIME ZONE,
    data_aprovacao DATE,
    observacoes_recusa TEXT,
    solicitante_telefone TEXT,
    solicitante_email TEXT,
    criado_por UUID,
    recusado_por UUID,
    resubmissoes INTEGER,
    observacoes_aprovacao TEXT
);

CREATE TABLE IF NOT EXISTS hub.agenda (
    id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(),
    titulo TEXT NOT NULL,
    descricao TEXT,
    data TIMESTAMPTZ NOT NULL,
    local TEXT,
    tipo TEXT,
    participantes TEXT[],
    created_at TIMESTAMPTZ DEFAULT NOW(),
    origem TEXT DEFAULT Alê Portela,
    hora TEXT,
    privacidade TEXT DEFAULT Público,
    solicitacao_id UUID
);

CREATE TABLE IF NOT EXISTS hub.recursos (
    id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(),
    municipio_id UUID,
    tipo CHARACTER VARYING NOT NULL,
    descricao TEXT NOT NULL,
    valor NUMERIC,
    origem CHARACTER VARYING,
    status CHARACTER VARYING DEFAULT Aprovado,
    data_aprovacao DATE,
    responsavel CHARACTER VARYING,
    observacoes TEXT,
    created_at TIMESTAMP WITHOUT TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS core.profiles (
    id UUID NOT NULL PRIMARY KEY,
    full_name TEXT NOT NULL,
    phone TEXT NOT NULL,
    email TEXT NOT NULL,
    role TEXT DEFAULT user,
    status TEXT DEFAULT active,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS core.notificacoes (
    id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(),
    usuario_id UUID,
    titulo TEXT NOT NULL,
    mensagem TEXT NOT NULL,
    link TEXT,
    lida BOOLEAN,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS core.notification_logs (
    id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(),
    created_at TIMESTAMPTZ DEFAULT NOW(),
    event_id UUID,
    recipient_id UUID,
    recipient_type TEXT NOT NULL,
    channel TEXT NOT NULL,
    status TEXT NOT NULL DEFAULT pending,
    error_message TEXT,
    message_sid TEXT,
    content TEXT,
    recipient_name TEXT,
    recipient_phone TEXT
);

CREATE TABLE IF NOT EXISTS core.role_permissions (
    role TEXT NOT NULL PRIMARY KEY,
    allowed_items TEXT[] NOT NULL,
    display_name TEXT
);


